code_examples.code:
#include <iostream>
#include <cstring>
#include <unistd.h>
#include <signal.h>
#include <sys/wait.h>
#include <sys/socket.h>
#include <arpa/inet.h>

// SIGCHLD handler to reap zombie processes
void sigchld_handler(int signum) {
    int saved_errno = errno;
    // Reap all dead children without blocking
    while (waitpid(-1, NULL, WNOHANG) > 0);
    errno = saved_errno;
}

void handle_client(int client_fd) {
    char buffer[1024];

    while (true) {
        ssize_t bytes = recv(client_fd, buffer, sizeof(buffer) - 1, 0);

        if (bytes <= 0) {
            if (bytes < 0) perror("recv");
            break;  // Connection closed or error
        }

        buffer[bytes] = '\0';
        std::cout << "Child PID " << getpid() << " received: " << buffer << "\n";

        // Echo back
        send(client_fd, buffer, bytes, MSG_NOSIGNAL);
    }

    std::cout << "Child PID " << getpid() << " closing connection\n";
}

int main() {
    // Install SIGCHLD handler
    struct sigaction sa;
    sa.sa_handler = sigchld_handler;
    sigemptyset(&sa.sa_mask);
    sa.sa_flags = SA_RESTART;  // Restart interrupted syscalls
    if (sigaction(SIGCHLD, &sa, NULL) < 0) {
        perror("sigaction");
        return 1;
    }

    // Create listening socket
    int server_fd = socket(AF_INET, SOCK_STREAM, 0);
    if (server_fd < 0) {
        perror("socket");
        return 1;
    }

    int opt = 1;
    setsockopt(server_fd, SOL_SOCKET, SO_REUSEADDR, &opt, sizeof(opt));

    sockaddr_in addr{};
    addr.sin_family = AF_INET;
    addr.sin_addr.s_addr = INADDR_ANY;
    addr.sin_port = htons(5000);

    if (bind(server_fd, (sockaddr*)&addr, sizeof(addr)) < 0) {
        perror("bind");
        close(server_fd);
        return 1;
    }

    if (listen(server_fd, 128) < 0) {
        perror("listen");
        close(server_fd);
        return 1;
    }

    std::cout << "Fork-based server listening on port 5000...\n";

    while (true) {
        sockaddr_in client_addr{};
        socklen_t client_len = sizeof(client_addr);
        int client_fd = accept(server_fd, (sockaddr*)&client_addr, &client_len);

        if (client_fd < 0) {
            if (errno == EINTR) continue;  // Interrupted by SIGCHLD, retry
            perror("accept");
            continue;
        }

        std::cout << "Parent: Accepted connection, forking...\n";

        pid_t pid = fork();

        if (pid < 0) {
            perror("fork");
            close(client_fd);
            continue;
        }

        if (pid == 0) {
            // Child process
            close(server_fd);  // Child doesn't need listening socket
            handle_client(client_fd);
            close(client_fd);
            exit(0);  // Child exits cleanly
        }

        // Parent process
        close(client_fd);  // Parent doesn't need client socket
        std::cout << "Parent: Forked child PID " << pid << "\n";
    }

    close(server_fd);
    return 0;
}

