    sa.sa_handler = sigchld_handler;
    sigemptyset(&sa.sa_mask);
    sa.sa_flags = SA_RESTART;  // Auto-restart interrupted syscalls
    sigaction(SIGCHLD, &sa, NULL);  // ✅ Reliable!

    // ... rest of code
}
```

