code_examples.code:
#include <iostream>
#include <cstring>
#include <unistd.h>
#include <sys/socket.h>
#include <sys/select.h>
#include <netinet/in.h>
#include <arpa/inet.h>

const int PORT = 8080;
const int BUFFER_SIZE = 1024;

int main() {
    // Create listening socket
    int server_fd = socket(AF_INET, SOCK_STREAM, 0);
    if (server_fd < 0) {
        perror("socket");
        return 1;
    }

    // Allow address reuse
    int opt = 1;
    setsockopt(server_fd, SOL_SOCKET, SO_REUSEADDR, &opt, sizeof(opt));

    // Bind to port
    struct sockaddr_in server_addr;
    server_addr.sin_family = AF_INET;
    server_addr.sin_addr.s_addr = INADDR_ANY;
    server_addr.sin_port = htons(PORT);

    if (bind(server_fd, (struct sockaddr*)&server_addr, sizeof(server_addr)) < 0) {
        perror("bind");
        close(server_fd);
        return 1;
    }

    // Listen
    if (listen(server_fd, 10) < 0) {
        perror("listen");
        close(server_fd);
        return 1;
    }

    std::cout << "Server listening on port " << PORT << "\n";

    // Initialize master fd_set
    fd_set master_fds;
    FD_ZERO(&master_fds);
    FD_SET(server_fd, &master_fds);
    int max_fd = server_fd;

    // Main loop
    while (true) {
        // Copy master to working set
        fd_set read_fds = master_fds;

        // Wait for activity
        int ready = select(max_fd + 1, &read_fds, NULL, NULL, NULL);

        if (ready < 0) {
            perror("select");
            break;
        }

        // Check each file descriptor
        for (int fd = 0; fd <= max_fd; fd++) {
            if (!FD_ISSET(fd, &read_fds)) {
                continue;  // Not ready
            }

            if (fd == server_fd) {
                // New connection on listening socket
                struct sockaddr_in client_addr;
                socklen_t addr_len = sizeof(client_addr);
                int new_client = accept(server_fd, (struct sockaddr*)&client_addr, &addr_len);

                if (new_client < 0) {
                    perror("accept");
                    continue;
                }

                // Add to master set
                FD_SET(new_client, &master_fds);
                if (new_client > max_fd) {
                    max_fd = new_client;
                }

                std::cout << "New client " << new_client << " connected from "
                          << inet_ntoa(client_addr.sin_addr) << "\n";

            } else {
                // Data from existing client
                char buffer[BUFFER_SIZE];
                int n = recv(fd, buffer, sizeof(buffer), 0);

                if (n <= 0) {
                    // Client disconnected or error
                    if (n == 0) {
                        std::cout << "Client " << fd << " disconnected\n";
                    } else {
                        perror("recv");
                    }

                    close(fd);
                    FD_CLR(fd, &master_fds);

                } else {
                    // Echo back to client
                    buffer[n] = '\0';
                    std::cout << "Client " << fd << ": " << buffer;

                    send(fd, buffer, n, 0);
                }
            }
        }
    }

    close(server_fd);
    return 0;
}

