#include <iostream>
#include <sys/epoll.h>
#include <sys/socket.h>
#include <netinet/in.h>
#include <unistd.h>
#include <cstring>
#include <fcntl.h>

const int PORT = 8080;
const int MAX_EVENTS = 128;
const int BUFFER_SIZE = 1024;

void set_nonblocking(int fd) {
    int flags = fcntl(fd, F_GETFL, 0);
    fcntl(fd, F_SETFL, flags | O_NONBLOCK);
}

int main() {
    // Create server socket
    int server_fd = socket(AF_INET, SOCK_STREAM, 0);
    if (server_fd < 0) {
        perror("socket");
        return 1;
    }

    int opt = 1;
    setsockopt(server_fd, SOL_SOCKET, SO_REUSEADDR, &opt, sizeof(opt));

    struct sockaddr_in server_addr;
    server_addr.sin_family = AF_INET;
    server_addr.sin_addr.s_addr = INADDR_ANY;
    server_addr.sin_port = htons(PORT);

    if (bind(server_fd, (struct sockaddr*)&server_addr, sizeof(server_addr)) < 0) {
        perror("bind");
        close(server_fd);
        return 1;
    }

    if (listen(server_fd, 128) < 0) {
        perror("listen");
        close(server_fd);
        return 1;
    }

    set_nonblocking(server_fd);

    std::cout << "Echo server listening on port " << PORT << " (epoll level-triggered)\n";

    // Create epoll instance
    int epfd = epoll_create1(0);
    if (epfd < 0) {
        perror("epoll_create1");
        close(server_fd);
        return 1;
    }

    // Add server socket to epoll
    struct epoll_event ev, events[MAX_EVENTS];
    ev.events = EPOLLIN;
    ev.data.fd = server_fd;

    if (epoll_ctl(epfd, EPOLL_CTL_ADD, server_fd, &ev) < 0) {
        perror("epoll_ctl");
        close(server_fd);
        close(epfd);
        return 1;
    }

    // Event loop
    while (true) {
        int nready = epoll_wait(epfd, events, MAX_EVENTS, -1);

        if (nready < 0) {
            perror("epoll_wait");
            break;
        }

        for (int i = 0; i < nready; i++) {
            int fd = events[i].data.fd;

            if (fd == server_fd) {
                // New connection
                struct sockaddr_in client_addr;
                socklen_t addr_len = sizeof(client_addr);
                int client_fd = accept(server_fd, (struct sockaddr*)&client_addr, &addr_len);

                if (client_fd < 0) {
                    perror("accept");
                    continue;
                }

                set_nonblocking(client_fd);

                // Add to epoll
                ev.events = EPOLLIN;
                ev.data.fd = client_fd;
                epoll_ctl(epfd, EPOLL_CTL_ADD, client_fd, &ev);

                std::cout << "Client " << client_fd << " connected\n";
            }
            else {
                // Client data
                if (events[i].events & EPOLLIN) {
                    char buffer[BUFFER_SIZE];
                    int n = recv(fd, buffer, sizeof(buffer), 0);

                    if (n <= 0) {
                        // Client disconnected or error
                        if (n == 0) {
                            std::cout << "Client " << fd << " disconnected\n";
                        } else {
                            perror("recv");
                        }

                        epoll_ctl(epfd, EPOLL_CTL_DEL, fd, NULL);
                        close(fd);
                    }
                    else {
                        // Echo back
                        buffer[n] = '\0';
                        std::cout << "Client " << fd << ": " << buffer;
                        send(fd, buffer, n, 0);
                    }
                }

                if (events[i].events & (EPOLLHUP | EPOLLERR)) {
                    std::cout << "Client " << fd << " error/hangup\n";
                    epoll_ctl(epfd, EPOLL_CTL_DEL, fd, NULL);
                    close(fd);
                }
            }
        }
    }

    close(epfd);
    close(server_fd);
    return 0;
}

#include <iostream>
#include <sys/epoll.h>
#include <sys/socket.h>
#include <netinet/in.h>
#include <unistd.h>
#include <fcntl.h>
#include <cstring>
#include <errno.h>

const int PORT = 8080;
const int MAX_EVENTS = 128;
const int BUFFER_SIZE = 1024;

void set_nonblocking(int fd) {
    int flags = fcntl(fd, F_GETFL, 0);
    fcntl(fd, F_SETFL, flags | O_NONBLOCK);
}

int main() {
    // Create server (same as Example 1)
    int server_fd = socket(AF_INET, SOCK_STREAM, 0);
    int opt = 1;
    setsockopt(server_fd, SOL_SOCKET, SO_REUSEADDR, &opt, sizeof(opt));

    struct sockaddr_in server_addr;
    server_addr.sin_family = AF_INET;
    server_addr.sin_addr.s_addr = INADDR_ANY;
    server_addr.sin_port = htons(PORT);

    bind(server_fd, (struct sockaddr*)&server_addr, sizeof(server_addr));
    listen(server_fd, 128);
    set_nonblocking(server_fd);

    std::cout << "Echo server on port " << PORT << " (EDGE-TRIGGERED)\n";

    // Create epoll with edge-triggered
    int epfd = epoll_create1(0);
    struct epoll_event ev, events[MAX_EVENTS];

    // Add server with EPOLLET
    ev.events = EPOLLIN | EPOLLET;
    ev.data.fd = server_fd;
    epoll_ctl(epfd, EPOLL_CTL_ADD, server_fd, &ev);

    while (true) {
        int nready = epoll_wait(epfd, events, MAX_EVENTS, -1);

        for (int i = 0; i < nready; i++) {
            int fd = events[i].data.fd;

            if (fd == server_fd) {
                // Accept ALL pending connections (edge-triggered)
                while (true) {
                    struct sockaddr_in client_addr;
                    socklen_t addr_len = sizeof(client_addr);
                    int client_fd = accept(server_fd, (struct sockaddr*)&client_addr, &addr_len);

                    if (client_fd < 0) {
                        if (errno == EAGAIN || errno == EWOULDBLOCK) {
                            break;  // No more pending connections
                        }
                        perror("accept");
                        break;
                    }

                    set_nonblocking(client_fd);

                    // Add with edge-triggered
                    ev.events = EPOLLIN | EPOLLET;
                    ev.data.fd = client_fd;
                    epoll_ctl(epfd, EPOLL_CTL_ADD, client_fd, &ev);

                    std::cout << "Client " << client_fd << " connected\n";
                }
            }
            else {
                if (events[i].events & EPOLLIN) {
                    // Read ALL available data (critical for edge-triggered!)
                    while (true) {
                        char buffer[BUFFER_SIZE];
                        int n = recv(fd, buffer, sizeof(buffer), 0);

                        if (n < 0) {
                            if (errno == EAGAIN || errno == EWOULDBLOCK) {
                                break;  // ✅ All data read
                            }

                            // Real error
                            perror("recv");
                            epoll_ctl(epfd, EPOLL_CTL_DEL, fd, NULL);
                            close(fd);
                            break;
                        }

                        if (n == 0) {
                            // EOF
                            std::cout << "Client " << fd << " disconnected\n";
                            epoll_ctl(epfd, EPOLL_CTL_DEL, fd, NULL);
                            close(fd);
                            break;
                        }

                        // Echo back
                        buffer[n] = '\0';
                        std::cout << "Client " << fd << ": " << buffer;
                        send(fd, buffer, n, MSG_NOSIGNAL);
                    }
                }

                if (events[i].events & (EPOLLHUP | EPOLLERR)) {
                    epoll_ctl(epfd, EPOLL_CTL_DEL, fd, NULL);
                    close(fd);
                }
            }
        }
    }

    close(epfd);
    close(server_fd);
    return 0;
}

#include <iostream>
#include <map>
#include <string>
#include <sys/epoll.h>
#include <sys/socket.h>
#include <netinet/in.h>
#include <arpa/inet.h>
#include <unistd.h>
#include <fcntl.h>
#include <cstring>

const int PORT = 8080;
const int MAX_EVENTS = 128;
const int BUFFER_SIZE = 1024;

struct ClientInfo {
    std::string name;
    std::string address;
};

std::map<int, ClientInfo> clients;

void set_nonblocking(int fd) {
    int flags = fcntl(fd, F_GETFL, 0);
    fcntl(fd, F_SETFL, flags | O_NONBLOCK);
}

void broadcast(const std::string& message, int sender_fd, int server_fd) {
    for (auto& pair : clients) {
        int fd = pair.first;
        if (fd != sender_fd && fd != server_fd) {
            send(fd, message.c_str(), message.size(), MSG_NOSIGNAL);
        }
    }
}

int main() {
    int server_fd = socket(AF_INET, SOCK_STREAM, 0);
    int opt = 1;
    setsockopt(server_fd, SOL_SOCKET, SO_REUSEADDR, &opt, sizeof(opt));

    struct sockaddr_in server_addr;
    server_addr.sin_family = AF_INET;
    server_addr.sin_addr.s_addr = INADDR_ANY;
    server_addr.sin_port = htons(PORT);

    bind(server_fd, (struct sockaddr*)&server_addr, sizeof(server_addr));
    listen(server_fd, 128);
    set_nonblocking(server_fd);

    std::cout << "Chat server on port " << PORT << "\n";

    int epfd = epoll_create1(0);
    struct epoll_event ev, events[MAX_EVENTS];

    ev.events = EPOLLIN;
    ev.data.fd = server_fd;
    epoll_ctl(epfd, EPOLL_CTL_ADD, server_fd, &ev);

    while (true) {
        int nready = epoll_wait(epfd, events, MAX_EVENTS, -1);

        for (int i = 0; i < nready; i++) {
            int fd = events[i].data.fd;

            if (fd == server_fd) {
                // New connection
                struct sockaddr_in client_addr;
                socklen_t addr_len = sizeof(client_addr);
                int client_fd = accept(server_fd, (struct sockaddr*)&client_addr, &addr_len);

                if (client_fd >= 0) {
                    set_nonblocking(client_fd);

                    ClientInfo info;
                    info.name = "User" + std::to_string(client_fd);
                    info.address = inet_ntoa(client_addr.sin_addr);
                    clients[client_fd] = info;

                    ev.events = EPOLLIN;
                    ev.data.fd = client_fd;
                    epoll_ctl(epfd, EPOLL_CTL_ADD, client_fd, &ev);

                    std::string welcome = "Welcome! You are " + info.name + "\n";
                    send(client_fd, welcome.c_str(), welcome.size(), 0);

                    std::string join_msg = info.name + " joined the chat\n";
                    std::cout << join_msg;
                    broadcast(join_msg, client_fd, server_fd);
                }
            }
            else {
                if (events[i].events & EPOLLIN) {
                    char buffer[BUFFER_SIZE];
                    int n = recv(fd, buffer, sizeof(buffer), 0);

                    if (n <= 0) {
                        // Disconnected
                        std::string goodbye = clients[fd].name + " left the chat\n";
                        std::cout << goodbye;
                        broadcast(goodbye, fd, server_fd);

                        epoll_ctl(epfd, EPOLL_CTL_DEL, fd, NULL);
                        clients.erase(fd);
                        close(fd);
                    }
                    else {
                        buffer[n] = '\0';
                        std::string message = clients[fd].name + ": " + buffer;
                        std::cout << message;
                        broadcast(message, fd, server_fd);
                    }
                }

                if (events[i].events & (EPOLLHUP | EPOLLERR)) {
                    if (clients.count(fd)) {
                        std::string goodbye = clients[fd].name + " disconnected\n";
                        std::cout << goodbye;
                        broadcast(goodbye, fd, server_fd);
                        clients.erase(fd);
                    }

                    epoll_ctl(epfd, EPOLL_CTL_DEL, fd, NULL);
                    close(fd);
                }
            }
        }
    }

    close(epfd);
    close(server_fd);
    return 0;
}

#include <iostream>
#include <map>
#include <queue>
#include <string>
#include <sys/epoll.h>
#include <sys/socket.h>
#include <netinet/in.h>
#include <unistd.h>
#include <fcntl.h>
#include <errno.h>

const int PORT = 8080;
const int MAX_EVENTS = 128;

std::map<int, std::queue<std::string>> write_queues;
int epfd;  // Global for update_events

void set_nonblocking(int fd) {
    int flags = fcntl(fd, F_GETFL, 0);
    fcntl(fd, F_SETFL, flags | O_NONBLOCK);
}

void update_events(int fd) {
    struct epoll_event ev;
    ev.data.fd = fd;

    if (write_queues[fd].empty()) {
        // No data to send - only monitor reads
        ev.events = EPOLLIN;
    } else {
        // Data pending - monitor reads AND writes
        ev.events = EPOLLIN | EPOLLOUT;
    }

    epoll_ctl(epfd, EPOLL_CTL_MOD, fd, &ev);
}

void queue_send(int fd, const std::string& data) {
    bool was_empty = write_queues[fd].empty();
    write_queues[fd].push(data);

    if (was_empty) {
        update_events(fd);  // Start monitoring EPOLLOUT
    }
}

int main() {
    int server_fd = socket(AF_INET, SOCK_STREAM, 0);
    int opt = 1;
    setsockopt(server_fd, SOL_SOCKET, SO_REUSEADDR, &opt, sizeof(opt));

    struct sockaddr_in server_addr;
    server_addr.sin_family = AF_INET;
    server_addr.sin_addr.s_addr = INADDR_ANY;
    server_addr.sin_port = htons(PORT);

    bind(server_fd, (struct sockaddr*)&server_addr, sizeof(server_addr));
    listen(server_fd, 128);
    set_nonblocking(server_fd);

    std::cout << "Server with EPOLLOUT on port " << PORT << "\n";

    epfd = epoll_create1(0);
    struct epoll_event ev, events[MAX_EVENTS];

    ev.events = EPOLLIN;
    ev.data.fd = server_fd;
    epoll_ctl(epfd, EPOLL_CTL_ADD, server_fd, &ev);

    while (true) {
        int nready = epoll_wait(epfd, events, MAX_EVENTS, -1);

        for (int i = 0; i < nready; i++) {
            int fd = events[i].data.fd;

            if (fd == server_fd) {
                int client_fd = accept(server_fd, NULL, NULL);
                if (client_fd >= 0) {
                    set_nonblocking(client_fd);

                    ev.events = EPOLLIN;
                    ev.data.fd = client_fd;
                    epoll_ctl(epfd, EPOLL_CTL_ADD, client_fd, &ev);

                    write_queues[client_fd] = std::queue<std::string>();
                    std::cout << "Client " << client_fd << " connected\n";
                }
            }
            else {
                if (events[i].events & EPOLLIN) {
                    char buffer[1024];
                    int n = recv(fd, buffer, sizeof(buffer), 0);

                    if (n <= 0) {
                        epoll_ctl(epfd, EPOLL_CTL_DEL, fd, NULL);
                        write_queues.erase(fd);
                        close(fd);
                    }
                    else {
                        // Queue large response (simulating heavy load)
                        buffer[n] = '\0';
                        std::string response = "ECHO: " + std::string(buffer);

                        // Multiply by 100 to test partial sends
                        std::string large_response;
                        for (int j = 0; j < 100; j++) {
                            large_response += response;
                        }

                        queue_send(fd, large_response);
                        std::cout << "Queued " << large_response.size()
                                  << " bytes for client " << fd << "\n";
                    }
                }

                if (events[i].events & EPOLLOUT) {
                    if (!write_queues[fd].empty()) {
                        std::string& data = write_queues[fd].front();

                        ssize_t sent = send(fd, data.c_str(), data.size(), MSG_NOSIGNAL);

                        if (sent > 0) {
                            std::cout << "Sent " << sent << " bytes to " << fd << "\n";

                            if (static_cast<size_t>(sent) < data.size()) {
                                // Partial send
                                data.erase(0, sent);
                            } else {
                                // Complete send
                                write_queues[fd].pop();
                            }

                            update_events(fd);  // Update based on queue state
                        }
                        else if (sent < 0 && errno != EAGAIN && errno != EWOULDBLOCK) {
                            epoll_ctl(epfd, EPOLL_CTL_DEL, fd, NULL);
                            write_queues.erase(fd);
                            close(fd);
                        }
                    }
                }

                if (events[i].events & (EPOLLHUP | EPOLLERR)) {
                    epoll_ctl(epfd, EPOLL_CTL_DEL, fd, NULL);
                    write_queues.erase(fd);
                    close(fd);
                }
            }
        }
    }

    close(epfd);
    close(server_fd);
    return 0;
}

