    std::mutex mutex;

public:
    void record(double latency_ms) {
        std::lock_guard<std::mutex> lock(mutex);
        latencies.push_back(latency_ms);

        // Keep only last 10,000 measurements
        if (latencies.size() > 10000) {
            latencies.erase(latencies.begin());
