timeout.tv_sec = 30;
timeout.tv_usec = 0;
setsockopt(fd, SOL_SOCKET, SO_RCVTIMEO, &timeout, sizeof(timeout));

int n = recv(fd, buf, sizeof(buf), 0);

if (n < 0 && errno == ETIMEDOUT) {
    std::cerr << "Receive timeout\n";
    // Retry or close
}
```

