        std::lock_guard<std::mutex> lock(mutex);

        if (latencies.empty()) return;

        std::sort(latencies.begin(), latencies.end());

        size_t p50 = latencies.size() * 50 / 100;
        size_t p95 = latencies.size() * 95 / 100;
        size_t p99 = latencies.size() * 99 / 100;

